<script lang="ts">export interface StageSpeaker{npcId:string;name:string;emotion?:string;outfit?:number;focus:boolean}let {speakers,portraitFor=()=>null}:{speakers:readonly StageSpeaker[];portraitFor?:(npcId:string,emotion?:string,outfit?:number)=>string|null}=$props();</script>
<div class="stage" aria-label="현재 화자">{#each speakers.slice(0,3) as speaker}{@const portrait=portraitFor(speaker.npcId,speaker.emotion,speaker.outfit)}<div class:focus={speaker.focus} class="standing"><div class="portrait">{#if portrait}<img src={portrait} alt={speaker.name}/>{:else}{speaker.name.slice(0,1).toUpperCase()}{/if}</div><strong>{speaker.name}</strong><span>{speaker.emotion??'default'}</span></div>{/each}</div>
<style>.stage{display:flex;justify-content:center;align-items:end;gap:var(--space-4);min-height:12rem;padding:var(--space-4);border-radius:var(--radius-lg);background:linear-gradient(180deg,transparent,var(--color-inset))}.standing{display:grid;justify-items:center;gap:var(--space-1);opacity:.55;transform:scale(.9)}.standing.focus{opacity:1;transform:scale(1)}.portrait{display:grid;place-items:center;width:7rem;aspect-ratio:3/4;border:1px solid var(--color-line);border-radius:var(--radius-lg) var(--radius-lg) 0 0;background:var(--color-panel);font-size:2rem;overflow:hidden}.portrait img{width:100%;height:100%;object-fit:contain;object-position:center bottom}.standing span{color:var(--color-muted);font-size:.75rem}@media(max-width:600px){.portrait{width:5rem}}</style>
